import './PopoverHelper.scss';

import { classNames } from ':helpers/classnames';
import React, { forwardRef } from 'react';

import { Popover } from '../Popover';
import type { PopoverHelperProps } from './PopoverHelper.types';
import { PopoverHelperContent } from './PopoverHelperContent';

export const PopoverHelper = forwardRef<HTMLDivElement, PopoverHelperProps>(
	(
		{
			open = false,
			title,
			body,
			disableHover,
			triggerMode = 'hover',
			children,
			className,
			popoverRootClassName,
			portalClassName,
			closeMode,
			closeOnScroll,
			onScroll,
			attachToChildren = false,
			placement = 'bottom',
		},
		ref,
	) => (
		<Popover
			popoverClassName={classNames('dsb_popover-content__helper', popoverRootClassName)}
			open={open}
			disableHover={disableHover}
			triggerMode={triggerMode}
			portalClassName={classNames('dsb_helper-portal', portalClassName)}
			closeMode={closeMode}
			closeOnScroll={closeOnScroll}
			onScroll={onScroll}
			content={<PopoverHelperContent ref={ref} title={title} body={body} className={className} />}
			attachToChildren={attachToChildren}
			placement={placement}
		>
			{children}
		</Popover>
	),
);
